const stations = $('Code in JavaScript').all().map(item => item.json);
const userMessage = $('Webhook').item.json.body.message;
const weatherData = $('HTTP Request1').all().map(item => item.json);

const stationsWithWeather = stations.map((station, index) => ({
  name: station.name,
  region: station.region,
  altitude_max: station.altitude_max,
  slopes: station.slopes,
  open: station.open,
  weather: {
    temperature: weatherData[index]?.current?.temperature_2m ?? 'N/A',
    snowfall: weatherData[index]?.current?.snowfall ?? 'N/A',
    windspeed: weatherData[index]?.current?.windspeed_10m ?? 'N/A'
  }
}));

return [{
  json: {
    body: JSON.stringify({
      model: "llama-3.3-70b-versatile",
      messages: [
        {
          role: "system",
          content: "Ești un asistent pentru stațiuni de ski din România. Răspunde întotdeauna în română. Folosește datele meteo live furnizate."
        },
        {
          role: "user",
          content: `${userMessage}\n\nDate stațiuni cu meteo live:\n${JSON.stringify(stationsWithWeather, null, 2)}`
        }
      ]
    })
  }
}];
